import { Food, NutritionFacts } from '@/types/food';

// Helper function to generate unique IDs
const generateId = (name: string, index: number) => 
  `${name.toLowerCase().replace(/\s+/g, '-')}-${index}`;

// Helper function to create complete nutrition facts
const createNutritionFacts = (
  servingSize: string,
  calories: number,
  protein: number,
  carbs: number,
  fats: number,
  options: Partial<NutritionFacts> = {}
): NutritionFacts => {
  // Calculate default values based on macros if not provided
  const saturatedFat = options.saturatedFat ?? fats * 0.3; // ~30% of total fat
  const transFat = options.transFat ?? 0;
  const cholesterol = options.cholesterol ?? 0;
  const sodium = options.sodium ?? 5;
  const dietaryFiber = options.dietaryFiber ?? carbs * 0.1; // ~10% of carbs
  const totalSugars = options.totalSugars ?? carbs * 0.3; // ~30% of carbs
  const addedSugars = options.addedSugars ?? 0;
  
  // Micronutrients - default values
  const vitaminD = options.vitaminD ?? 0;
  const calcium = options.calcium ?? 20;
  const iron = options.iron ?? 0.5;
  const potassium = options.potassium ?? 100;
  
  return {
    servingSize,
    calories,
    totalFat: fats,
    saturatedFat,
    transFat,
    cholesterol,
    sodium,
    totalCarbohydrates: carbs,
    dietaryFiber,
    totalSugars,
    addedSugars,
    protein,
    vitaminD,
    calcium,
    iron,
    potassium,
    ...options,
  };
};

